1	// app/src/repositories/claim.repository.ts — claims + line-items persistence (Drizzle typed queries).
2	
3	import { randomUUID } from "node:crypto";
4	import { eq } from "drizzle-orm";
5	import type { Db } from "../db/connection";
6	import { claims, lineItems } from "../db/schema";
7	import type { ClaimStatus } from "../domain/entities/claim";
8	import type { LineItemStatus } from "../domain/entities/line-item";
9	
10	export type NewClaim = {
11	  memberId: string;
12	  policyId: string;
13	  serviceDate: string;
14	  provider?: string | null;
15	  diagnosisCode?: string | null;
16	};
17	
18	export type NewLine = {
19	  serviceCode: string;
20	  billedCents: number;
21	  units?: number | undefined;
22	  priorAuthPresent?: boolean | undefined;
23	  fingerprint: string;
24	};
25	
26	export type PersistedLine = {
27	  id: string;
28	  serviceCode: string;
29	  billedCents: number;
30	  units: number;
31	  priorAuthPresent: boolean;
32	  fingerprint: string;
33	};
34	
35	export type LineRecord = {
36	  id: string;
37	  claimId: string;
38	  serviceCode: string;
39	  billedCents: number;
40	  units: number;
41	  priorAuthPresent: boolean;
42	  status: LineItemStatus;
43	  fingerprint: string;
44	};
45	
46	export type ClaimRecord = {
47	  id: string;
48	  memberId: string;
49	  policyId: string;
50	  serviceDate: string;
51	  status: ClaimStatus;
52	};
53	
54	export function createClaimRepository(db: Db) {
55	  return {
56	    db,
57	
58	    insertClaim(c: NewClaim): string {
59	      const id = randomUUID(); // status defaults to SUBMITTED; aggregated status set later
60	      db.insert(claims)
61	        .values({
62	          id,
63	          memberId: c.memberId,
