1	import { describe, expect, it } from "vitest";
2	import { freshDb, makeClaimService, seedWorld } from "./db-helpers";
3	
4	// Cycle 26 — a full claim runs through the real SQLite store: it persists (claim + lines +
5	// one adjudication per line), advances the accumulators, writes adjudications append-only, and
6	// does it all in ONE transaction (a mid-write failure leaves nothing behind).
7	
8	describe("adjudicateClaim — full-claim writeback (cycle 26)", () => {
9	  // Two covered lines: PREVENTIVE (full coverage, no member share) + PCP_VISIT ($25 copay → OOP).
10	  const seedAndAdjudicate = () => {
11	    const { db, sqlite } = freshDb();
12	    const { memberId } = seedWorld(db, {
13	      rules: [
14	        { serviceCode: "PREVENTIVE", costShare: { type: "full_coverage" } },
15	        {
16	          serviceCode: "PCP_VISIT",
17	          costShare: { type: "copay", copayCents: 2_500 },
18	        },
19	      ],
20	    });
21	    const service = makeClaimService({ db, sqlite });
22	    service.adjudicateClaim({
23	      memberId,
24	      serviceDate: "2026-06-19",
25	      lineItems: [
26	        { serviceCode: "PREVENTIVE", billedCents: 12_000 },
27	        { serviceCode: "PCP_VISIT", billedCents: 18_000 },
28	      ],
29	    });
30	    return { db, sqlite };
31	  };
32	
33	  it("persists the claim, its line items, and one adjudication per line", () => {
34	    const { sqlite } = seedAndAdjudicate();
35	
36	    const claimRows = sqlite.prepare("SELECT * FROM claims").all() as {
37	      status: string;
38	    }[];
39	    const lineRows = sqlite.prepare("SELECT * FROM line_items").all();
40	    const adjRows = sqlite.prepare("SELECT * FROM adjudications").all();
41	
42	    expect(claimRows).toHaveLength(1);
43	    expect(claimRows[0]?.status).toBe("APPROVED"); // both lines approved → claim APPROVED
44	    expect(lineRows).toHaveLength(2);
45	    expect(adjRows).toHaveLength(2); // exactly one decision per line
46	  });
47	
48	  it("advances and persists the OOP accumulator by the copay amount", () => {
49	    const { sqlite } = seedAndAdjudicate();
50	
51	    const oop = sqlite
52	      .prepare("SELECT used_cents FROM accumulators WHERE dimension = 'OOP'")
53	      .get() as { used_cents: number } | undefined;
54	    expect(oop?.used_cents).toBe(2_500); // the $25 copay accrued to OOP
55	  });
56	
57	  it("writes adjudications append-only — a direct UPDATE is rejected by the DB", () => {
58	    const { sqlite } = seedAndAdjudicate();
59	
60	    expect(() =>
61	      sqlite.exec("UPDATE adjudications SET payable_cents = 0"),
62	    ).toThrow(/append-only/);
63	  });
64	
65	  it("adjudicates the whole claim in ONE transaction — a mid-write failure rolls back everything", () => {
66	    const { db, sqlite } = freshDb();
67	    const { memberId } = seedWorld(db, {
68	      rules: [
69	        { serviceCode: "PREVENTIVE", costShare: { type: "full_coverage" } },
70	        {
71	          serviceCode: "PCP_VISIT",
72	          costShare: { type: "copay", copayCents: 2_500 },
73	        },
74	      ],
75	    });
76	
77	    // Sabotage the second adjudication write to simulate a failure partway through the claim.
78	    const base = makeClaimService({ db, sqlite });
79	    let appendCalls = 0;
80	    const service = makeClaimService(
81	      { db, sqlite },
82	      {
83	        adjudications: {
84	          ...base.adjudications,
85	          append: (...args: unknown[]) => {
86	            appendCalls += 1;
87	            if (appendCalls === 2)
88	              throw new Error("simulated mid-claim failure");
89	            return (
90	              base.adjudications as { append: (...a: unknown[]) => unknown }
91	            ).append(...args);
92	          },
93	        } as typeof base.adjudications,
94	      },
95	    );
96	
97	    expect(() =>
98	      service.adjudicateClaim({
99	        memberId,
100	        serviceDate: "2026-06-19",
101	        lineItems: [
102	          { serviceCode: "PREVENTIVE", billedCents: 12_000 },
103	          { serviceCode: "PCP_VISIT", billedCents: 18_000 },
104	        ],
105	      }),
106	    ).toThrow(/simulated mid-claim failure/);
107	
108	    // Nothing persisted — the whole claim rolled back as one unit.
109	    const counts = (table: string) =>
110	      (sqlite.prepare(`SELECT count(*) c FROM ${table}`).get() as { c: number })
111	        .c;
112	    expect(counts("claims")).toBe(0);
113	    expect(counts("line_items")).toBe(0);
114	    expect(counts("adjudications")).toBe(0);
115	    expect(counts("accumulators")).toBe(0);
116	  });
117	});
