      ],
    });
    return { handle, service: makeClaimService(handle), memberId };
  };

  // The (status, reasons) of every adjudicated line under one claim.
  const decisionsFor = (sqlite: RawDb, claimId: string) =>
    (
      sqlite
        .prepare(
