61	          memberResponsibilityCents: a.memberResponsibilityCents,
62	          reasonsJson: a.reasons,
63	          explanation: a.explanation,
64	          deltaDeductibleIncCents: a.deltas.deductibleIncCents,
65	          deltaOopIncCents: a.deltas.oopIncCents,
66	          deltaLimitInc: a.deltas.limitInc,
67	        })
68	        .run();
69	      return id;
70	    },
71	
72	    // Has any OTHER line item sharing this fingerprint already been adjudicated?
73	    // Drives the DUPLICATE_LINE_ITEM gate: a resubmitted identical line is denied. The
74	    // adjudications JOIN is what makes within-claim batches correct — sibling lines exist as
75	    // rows before adjudication starts, so only ones already DECIDED count as a prior.
76	    existsForFingerprint(
77	      fingerprint: string,
78	      excludeLineItemId: string,
79	    ): boolean {
80	      const row = db.get<{ n: number }>(sql`
81	        SELECT COUNT(*) AS n
82	        FROM adjudications a
83	        JOIN line_items li ON li.id = a.line_item_id
84	        WHERE li.fingerprint = ${fingerprint}
85	          AND li.id != ${excludeLineItemId}
86	      `);
87	      return (row?.n ?? 0) > 0;
88	    },
89	
90	    // The current (latest seq) decision for a line — the one a dispute challenges.
91	    currentForLine(lineItemId: string): CurrentAdjudication | undefined {
92	      const row = db
93	        .select()
94	        .from(adjudications)
95	        .where(eq(adjudications.lineItemId, lineItemId))
96	        .orderBy(desc(adjudications.seq))
97	        .limit(1)
98	        .get();
99	      if (!row) return undefined;
100	      return {
101	        id: row.id,
102	        seq: row.seq,
103	        status: row.status,
104	        payableCents: row.payableCents,
105	        memberResponsibilityCents: row.memberResponsibilityCents,
106	        reasons: row.reasonsJson,
107	        explanation: row.explanation,
108	        deltas: {
109	          deductibleIncCents: row.deltaDeductibleIncCents,
110	          oopIncCents: row.deltaOopIncCents,
111	          limitInc: row.deltaLimitInc,
112	        },
113	      };
114	    },
115	
116	    // Each line's CURRENT decision (its max-seq adjudication) for one claim — for re-aggregation.
117	    currentOutcomesByClaim(
118	      claimId: string,
119	    ): { status: "APPROVED" | "DENIED"; reasons: ReasonCode[] }[] {
120	      const rows = db.all<{
121	        status: "APPROVED" | "DENIED";
122	        reasons_json: string;
123	      }>(sql`
124	        SELECT a.status AS status, a.reasons_json AS reasons_json
125	        FROM line_items li
126	        JOIN adjudications a ON a.line_item_id = li.id
127	        WHERE li.claim_id = ${claimId}
128	          AND a.seq = (SELECT MAX(seq) FROM adjudications WHERE line_item_id = li.id)
129	      `);
130	      return rows.map((r) => ({
131	        status: r.status,
132	        reasons: JSON.parse(r.reasons_json) as ReasonCode[],
133	      }));
134	    },
135	
136	    // Each line's CURRENT decision (its max-seq adjudication) for one claim, with the full
137	    // EOB payload — feeds GET /claims/:id/explanation and the claim-level payable sum.
138	    byClaimId(claimId: string): ClaimAdjudicationLine[] {
139	      const rows = db.all<{
140	        line_item_id: string;
141	        service_code: string;
142	        billed_cents: number;
143	        status: "APPROVED" | "DENIED";
144	        payable_cents: number;
145	        member_responsibility_cents: number;
146	        reasons_json: string;
147	        explanation: string;
148	      }>(sql`
149	        SELECT li.id AS line_item_id,
150	               li.service_code AS service_code,
151	               a.billed_cents AS billed_cents,
152	               a.status AS status,
153	               a.payable_cents AS payable_cents,
154	               a.member_responsibility_cents AS member_responsibility_cents,
155	               a.reasons_json AS reasons_json,
156	               a.explanation AS explanation
157	        FROM line_items li
158	        JOIN adjudications a ON a.line_item_id = li.id
159	        WHERE li.claim_id = ${claimId}
160	          AND a.seq = (SELECT MAX(seq) FROM adjudications WHERE line_item_id = li.id)
161	        ORDER BY li.created_at, li.id
162	      `);
163	      return rows.map((r) => ({
164	        lineItemId: r.line_item_id,
165	        serviceCode: r.service_code,
166	        billedCents: r.billed_cents,
167	        status: r.status,
168	        payableCents: r.payable_cents,
169	        memberResponsibilityCents: r.member_responsibility_cents,
170	        reasons: JSON.parse(r.reasons_json) as ReasonCode[],
171	        explanation: r.explanation,
172	      }));
173	    },
174	  };
175	}
